#!/usr/bin/env python3
"""
WORLDFIRST_SELFEXTRACT_CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5.py
Reconstructs: CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5.zip (embedded) and extracts to F:\CAPSTONE\packs\CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5\

Usage:
  python WORLDFIRST_SELFEXTRACT_CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5.py
  python WORLDFIRST_SELFEXTRACT_CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5.py --out "F:/CAPSTONE/packs"
"""
from __future__ import annotations
import argparse, base64, zipfile
from pathlib import Path
PAYLOAD_B64 = """"""

def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out", default="F:/CAPSTONE/packs")
    args = ap.parse_args()
    out_dir = Path(args.out); out_dir.mkdir(parents=True, exist_ok=True)
    zip_path = out_dir / "CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5.zip"
    zip_path.write_bytes(base64.b64decode(PAYLOAD_B64.encode("ascii")))
    target = out_dir / "CAPSTONE_PORTFOLIO_STACK_v2026-01-23.5"
    if target.exists():
        raise SystemExit(f"[FAIL] target folder exists: {target}")
    with zipfile.ZipFile(zip_path, "r") as z:
        z.extractall(target)
    print("[OK] wrote:", zip_path)
    print("[OK] extracted to:", target)

if __name__ == "__main__":
    main()
